mapper.sql:
WITH RECURSIVE CTG_HIERARCHY AS ( SELECT 1 AS LEVEL, TEMP_PSC.STD_CTG_NO, TEMP_PSC.UPR_STD_CTG_NO, TEMP_PSC.MRGN_RATE FROM PR_STD_CTG TEMP_PSC WHERE 1 = 1
AND TEMP_PSC.STD_CTG_NO = #{stdCtgNo}
UNION ALL SELECT LEVEL + 1 AS LEVEL, RECUR_PSC.STD_CTG_NO, RECUR_PSC.UPR_STD_CTG_NO, RECUR_PSC.MRGN_RATE FROM PR_STD_CTG RECUR_PSC JOIN CTG_HIERARCHY H ON RECUR_PSC.STD_CTG_NO = H.UPR_STD_CTG_NO )

mapper.select:
/* StandardCategoryQueryMyBatisDao.getStandardCategoryMgmtChildListCount */
SELECT COUNT(1)
FROM PR_STD_CTG PSC
WHERE PSC.UPR_STD_CTG_NO = #{stdCtgNo}

/* StandardCategoryQueryMyBatisDao.getStandardCategoryMgmtGoodsListCount */
SELECT COUNT(1)
FROM   PR_GOODS_BASE PGB
WHERE  PGB.STD_CTG_NO = #{stdCtgNo}
  AND  PGB.SALE_STAT_CD IN ('10', '20')

/* StandardCategoryQueryMyBatisDao.getStandardCategoryMgmtGoodsList */
SELECT PGB.GOODS_NO
     , PGBM.GOODS_NM
     , FN_GET_CODENAME('PR005', PGB.SALE_STAT_CD) AS SALE_STAT_CD_NM
FROM   PR_GOODS_BASE PGB
           INNER JOIN PR_GOODS_BASE_ML PGBM ON PGB.GOODS_NO = PGBM.GOODS_NO AND PGBM.LANG_CD = #{langCd}
WHERE  PGB.STD_CTG_NO = #{stdCtgNo}
  AND  PGB.SALE_STAT_CD IN ('10', '20')
ORDER BY PGB.GOODS_NO DESC
LIMIT #{rowsPerPage} OFFSET (#{pageIdx} - 1) * #{rowsPerPage}

/* StandardCategoryQueryMyBatisDao.getStandardCategoryGoodsAttrListCount */
SELECT COUNT(1)
FROM   PR_STD_CTG_GOODS_ATT_INFO PSCGAI
           INNER JOIN PR_ATT_CD_INFO PACI ON PSCGAI.ATT_CD = PACI.ATT_CD
           INNER JOIN PR_ATT_CD_INFO_ML PACIM ON PACIM.ATT_CD = PSCGAI.ATT_CD AND PACIM.LANG_CD = #{langCd}
WHERE  PSCGAI.STD_CTG_NO = #{stdCtgNo}

/* StandardCategoryQueryMyBatisDao.getStandardCategoryDisplayListCount */
SELECT COUNT(1)
FROM PR_STD_CTG_DISP_INFO PSCDI
WHERE PSCDI.STD_CTG_NO = #{stdCtgNo}
  AND PSCDI.DEL_YN = 'N'
